// Normalize incoming draft records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    draftId: String(j.draftId ?? j.id ?? '').trim(),
    topic: typeof j.topic === 'string' ? j.topic.trim() : j.topic ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;
